import { useState } from "react";

const Experience = () => {
  const [hoveredId, setHoveredId] = useState<string | null>(null);

  const experience = [
    {
      id: "1",
      role: "Rust Software Engineer",
      company: "Revelo",
      duration: "2025 – Present",
      description: [
        "Responsible for developing high-performance systems in Rust, ensuring memory safety and reliability, while supporting AI model training and evaluation processes.",
      ],
      technologies: ["Rust"],
    },
  ];

  return (
    <section className="w-full max-w-4xl py-12 mx-auto" id="experience">
      <h2 className="text-2xl font-normal text-gray-200 mb-7">EXPERIENCE</h2>

      <div className="space-y-8">
        {experience.map((job) => (
          <article
            key={job.id}
            className="relative group"
            onMouseEnter={() => setHoveredId(job.id)}
            onMouseLeave={() => setHoveredId(null)}
          >
            <div className="p-6 transition-all duration-300 border border-gray-700 rounded-lg hover:border-gray-600 hover:bg-slate-800/30">
              <div className="flex flex-col mb-4 md:flex-row md:items-start md:justify-between">
                <div className="flex-1">
                  <h3
                    className={`text-lg font-semibold transition-colors duration-300 mb-1 ${
                      hoveredId === job.id ? "text-gray-200" : "text-gray-300"
                    }`}
                  >
                    {job.role} · {job.company}
                  </h3>
                  <time className="text-sm tracking-wide text-gray-400 uppercase">
                    {job.duration}
                  </time>
                </div>
              </div>

              <p className="mb-4 text-sm leading-relaxed text-gray-400">
                {job.description}
              </p>

              <div className="flex flex-wrap gap-2">
                {job.technologies.map((tech, index) => (
                  <span
                    key={index}
                    className={`px-3 py-1 text-xs font-medium rounded-full transition-colors duration-300 ${
                      hoveredId === job.id
                        ? "bg-gray-600/50 text-gray-200"
                        : "bg-gray-700/50 text-gray-300"
                    }`}
                  >
                    {tech}
                  </span>
                ))}
              </div>
            </div>
          </article>
        ))}
      </div>
      <a
        href="/sholeye_resume.pdf"
        className="inline-flex items-center gap-2 px-4 py-2 text-white text-xl transition-colors mt-2 hover:text-gray-300"
        target="_blank"
        rel="noopener noreferrer"
      >
        View Full Resume ➡
      </a>
    </section>
  );
};

export default Experience;
